<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'
import { Edit, Plus, Search, Upload } from '@element-plus/icons-vue'
import { ElMessage, type UploadFile } from 'element-plus'
import { adminApi, catalogApi, fileApi, type Brand, type Category, type ProductListItem } from '@/api/services'
const keyword = ref(''); const products = ref<ProductListItem[]>([]); const total = ref(0); const loading = ref(false); const dialog = ref(false); const categories = ref<Category[]>([]); const brands = ref<Brand[]>([]); const imageMode = ref<'url' | 'file'>('url'); const pendingFile = ref<UploadFile>(); const uploading = ref(false); const form = reactive({ title: '', subtitle: '', description: '', mainImageUrl: '', categoryId: undefined as number | undefined, brandId: undefined as number | undefined, status: 1 })
const load = async () => { loading.value = true; try { const page = await adminApi.products({ keyword: keyword.value || undefined, page: 1, size: 20 }); products.value = page.items; total.value = page.total } finally { loading.value = false } }; const openCreate = async () => { [categories.value, brands.value] = await Promise.all([catalogApi.categories(), catalogApi.brands()]); Object.assign(form, { title: '', subtitle: '', description: '', mainImageUrl: '', categoryId: undefined, brandId: undefined, status: 1 }); pendingFile.value = undefined; imageMode.value = 'url'; dialog.value = true }; const uploadImage = async () => { if (!pendingFile.value?.raw) return ElMessage.warning('请先选择图片文件'); uploading.value = true; try { const result = await fileApi.upload(pendingFile.value.raw); form.mainImageUrl = result.url; ElMessage.success('图片上传成功，可继续保存商品') } catch { ElMessage.error('上传接口暂未可用，请配置 VITE_FILE_UPLOAD_PATH 或改用图片 URL') } finally { uploading.value = false } }; const save = async () => { if (!form.mainImageUrl) return ElMessage.warning(imageMode.value === 'file' ? '请先完成图片上传并取得 URL' : '请填写商品图片 URL'); await adminApi.createProduct(form); ElMessage.success('商品已创建'); dialog.value = false; load() }; const onFileChange = (file: UploadFile) => { pendingFile.value = file; form.mainImageUrl = '' }; onMounted(load)
</script>
<template><div><div class="admin-page-title"><div><span>商品中心</span><h1>商品管理</h1><p>管理商品上架状态、价格与库存。</p></div><el-button type="primary" :icon="Plus" @click="openCreate">新增商品</el-button></div><section class="admin-card"><div class="toolbar"><el-input v-model="keyword" placeholder="搜索商品名称" :prefix-icon="Search" clearable @keyup.enter="load" /><el-button @click="load">筛选</el-button></div><el-table v-loading="loading" :data="products" style="width: 100%"><el-table-column label="商品信息" min-width="310"><template #default="scope"><div class="table-product"><img :src="scope.row.mainImageUrl || 'https://placehold.co/100x100/eaf3ff/1677ff?text=DingDong'" :alt="scope.row.title" /><div><b>{{ scope.row.title }}</b><small>{{ scope.row.subtitle }}</small></div></div></template></el-table-column><el-table-column label="售价" width="120"><template #default="scope">¥{{ Number(scope.row.minPrice ?? scope.row.price ?? 0).toFixed(2) }}</template></el-table-column><el-table-column prop="sales" label="销量" width="100" /><el-table-column label="操作" width="160"><template #default><el-button text type="primary" :icon="Edit">编辑</el-button></template></el-table-column></el-table><div class="admin-pagination"><el-pagination background layout="total, prev, pager, next" :total="total" /></div></section><el-dialog v-model="dialog" title="新增商品" width="650px"><el-form :model="form" label-width="95px"><el-form-item label="商品名称" required><el-input v-model="form.title" /></el-form-item><el-form-item label="商品副标题"><el-input v-model="form.subtitle" /></el-form-item><el-form-item label="商品描述"><el-input v-model="form.description" type="textarea" /></el-form-item><el-form-item label="商品图片" required><el-radio-group v-model="imageMode"><el-radio-button label="url">图片 URL</el-radio-button><el-radio-button label="file">本地文件</el-radio-button></el-radio-group><el-input v-if="imageMode === 'url'" v-model="form.mainImageUrl" placeholder="https://example.com/product.png" style="margin-top: 12px" /><div v-else class="upload-placeholder"><el-upload :auto-upload="false" :limit="1" @change="onFileChange"><el-button :icon="Upload">选择图片文件</el-button></el-upload><el-button type="primary" plain :loading="uploading" :disabled="!pendingFile" @click="uploadImage">上传并获取 URL</el-button><p v-if="form.mainImageUrl">上传成功：{{ form.mainImageUrl }}</p><p v-else>调用独立文件上传接口，成功后回填 URL，再提交商品信息。</p></div></el-form-item><el-form-item label="分类" required><el-select v-model="form.categoryId" style="width: 100%"><el-option v-for="item in categories" :key="item.id" :label="item.name" :value="item.id" /></el-select></el-form-item><el-form-item label="品牌" required><el-select v-model="form.brandId" style="width: 100%"><el-option v-for="item in brands" :key="item.id" :label="item.name" :value="item.id" /></el-select></el-form-item></el-form><template #footer><el-button @click="dialog = false">取消</el-button><el-button type="primary" @click="save">保存商品</el-button></template></el-dialog></div></template>
